import React, { useState } from 'react';
import axios from 'axios';
import './App.css';
import { marked } from 'marked';

const LANGUAGES = {
  en: { name: 'English', flag: '🇬🇧' },
  zh: { name: '中文', flag: '🇨🇳' },
  es: { name: 'Español', flag: '🇪🇸' },
  fr: { name: 'Français', flag: '🇫🇷' }
};

function App() {
  const [user, setUser] = useState(null);
  const [input, setInput] = useState('');
  const [chatHistory, setChatHistory] = useState([]);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [isLogin, setIsLogin] = useState(true);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [isHybridPlanModalOpen, setIsHybridPlanModalOpen] = useState(false);
  const [isContactAgentModalOpen, setIsContactAgentModalOpen] = useState(false);
  const [uploadedFiles, setUploadedFiles] = useState([]);
  const [showFileUpload, setShowFileUpload] = useState(false);
  const [isLanguageDropdownOpen, setIsLanguageDropdownOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [currentLanguage, setCurrentLanguage] = useState('en');

  const addMessage = (role, content) => {
    setChatHistory(prev => [...prev, {
      role,
      content,
      timestamp: new Date().toISOString()
    }]);
  };

  const handleSendMessage = async () => {
    if (!input && uploadedFiles.length === 0) return;
    
    addMessage('user', input);
    setInput('');
    setShowFileUpload(false);
    setIsProcessing(true);
    
    try {
      const formData = new FormData();
      formData.append('message', input);
      formData.append('language', currentLanguage);
      uploadedFiles.forEach(file => formData.append('files', file));

      const response = await axios.post('/api/chat', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });

      addMessage('ai', response.data.response);
      setUploadedFiles([]);
    } catch (error) {
      console.error('Error sending message:', error);
      addMessage('ai', "Sorry, I encountered an error. Please try again later.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileSelect = (e) => {
    const files = Array.from(e.target.files).filter(file => file.size <= 5 * 1024 * 1024);
    if (files.length !== e.target.files.length) {
      alert('Some files were too large (max 5MB) and were not added.');
    }
    setUploadedFiles(prev => [...prev, ...files]);
    e.target.value = '';
  };

  const removeFile = (index) => {
    setUploadedFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleLogin = async () => {
    try {
      const response = await axios.post('/api/login', { email, password });
      localStorage.setItem('token', response.data.token);
      setUser(response.data.user);
      setIsAuthModalOpen(false);
      addMessage('ai', `Welcome back, ${response.data.user.name}! How can I assist with your immigration needs today?`);
    } catch (error) {
      alert(error.response?.data?.error || 'Login failed. Please check your credentials.');
    }
  };

  const handleRegister = async () => {
    if (password !== confirmPassword) {
      alert('Passwords do not match');
      return;
    }
    try {
      const response = await axios.post('/api/register', { name, email, password });
      localStorage.setItem('token', response.data.token);
      setUser(response.data.user);
      setIsAuthModalOpen(false);
      addMessage('ai', `Welcome to AI-MMI, ${response.data.user.name}! Let's get started with your immigration journey.`);
    } catch (error) {
      alert(error.response?.data?.error || 'Registration failed. Please try again.');
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    setUser(null);
    addMessage('ai', "You have been logged out. Please log in again to access your profile.");
  };

  return (
    <div className="app-container">
      <header className="header">
        <div className="header-brand">
          <img 
            src="https://i.ibb.co/pjR8wxhR/ai-mmi-logo-dark-background.png" 
            alt="AI-MMI Logo" 
            className="header-icon" 
          />
          <h1 className="header-title">AI-MMI</h1>
        </div>
        
        <div className="header-controls">
          <div className="language-dropdown">
            <img 
              src="https://i.ibb.co/tMDdT4bd/icon-lang.png" 
              alt="Language" 
              className="header-icon" 
              onClick={() => setIsLanguageDropdownOpen(!isLanguageDropdownOpen)}
            />
            {isLanguageDropdownOpen && (
              <div className="language-options">
                {Object.entries(LANGUAGES).map(([code, lang]) => (
                  <button 
                    key={code} 
                    onClick={() => {
                      setCurrentLanguage(code);
                      setIsLanguageDropdownOpen(false);
                    }}
                    className={currentLanguage === code ? 'active' : ''}
                  >
                    {lang.flag} {lang.name}
                  </button>
                ))}
              </div>
            )}
          </div>
          <img 
            src={user ? "https://i.imgur.com/FcJiNT7.png" : "https://i.ibb.co/3mmnZvWc/icon-member.png"} 
            alt="User" 
            className="header-icon" 
            onClick={user ? handleLogout : () => setIsAuthModalOpen(true)}
          />
        </div>
      </header>

      <div className="main-content">
        <div className="chat-container">
          <div className="chat-history">
            {chatHistory.length === 0 ? (
              <div className="welcome-message">
                <h2>Welcome to AI-MMI Immigration Assistant</h2>
                <p>Ask me anything about visas, immigration processes, or upload your documents for analysis.</p>
              </div>
            ) : (
              chatHistory.map((msg, index) => (
                <div key={index} className={`message ${msg.role}-message`}>
                  <div dangerouslySetInnerHTML={{ __html: marked.parse(msg.content) }} />
                  <div className="timestamp">{new Date(msg.timestamp).toLocaleTimeString()}</div>
                </div>
              ))
            )}
            {isProcessing && (
              <div className="message ai-message">
                <div className="text-center">
                  <div className="spinner-border spinner-border-sm" role="status"></div> Processing...
                </div>
              </div>
            )}
          </div>
          
          <div className="input-area">
            {showFileUpload && (
              <div className="file-upload-container">
                <div className="file-previews">
                  {uploadedFiles.map((file, index) => (
                    <div key={index} className="file-preview">
                      <i className={`fas ${
                        file.type === 'application/pdf' ? 'fa-file-pdf' :
                        file.type.includes('word') ? 'fa-file-word' :
                        file.type === 'text/plain' ? 'fa-file-alt' :
                        file.type.includes('image') ? 'fa-file-image' : 'fa-file'
                      } file-icon`}></i>
                      <span className="file-name">{file.name}</span>
                      <button 
                        className="remove-file-btn"
                        onClick={() => removeFile(index)}
                      >
                        <i className="fas fa-times"></i>
                      </button>
                    </div>
                  ))}
                </div>
                <label htmlFor="fileUpload" className="btn btn-custom-outline">
                  <i className="fas fa-plus"></i> Add Files
                </label>
                <input 
                  type="file" 
                  id="fileUpload" 
                  multiple 
                  style={{ display: 'none' }} 
                  onChange={handleFileSelect}
                  accept=".pdf,.doc,.docx,.txt,.png,.jpg,.jpeg"
                />
                <p className="file-upload-note">Supported: PDF, Word, TXT, PNG, JPG (Max 5MB each)</p>
              </div>
            )}
            
            <div className="input-group">
              <button 
                className="btn btn-custom-outline attachment-btn" 
                onClick={() => setShowFileUpload(!showFileUpload)}
              >
                <i className="fas fa-paperclip"></i>
              </button>
              <textarea
                className="chat-input"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSendMessage();
                  }
                }}
                placeholder={`Type your question in ${LANGUAGES[currentLanguage].name}...`}
                rows={3}
              />
              <button 
                className="btn btn-custom send-btn" 
                onClick={handleSendMessage}
                disabled={(!input && uploadedFiles.length === 0) || isProcessing}
              >
                <i className="fas fa-paper-plane"></i>
              </button>
            </div>
          </div>
        </div>
        
        {/* Sidebar with all buttons */}
        <div className="sidebar">
          <div className="sidebar-container">
            <div className="promo-banner">
              <button 
                className="btn btn-custom" 
                onClick={() => setIsContactAgentModalOpen(true)}
              >
                Contact a Migration Lawyer/Agent
              </button>
            </div>
            <div className="sidebar-item" onClick={() => alert('Free assessment clicked')}>
              <span className="sidebar-icon"></span> Free assessment
            </div>
            <div className="sidebar-item" onClick={() => alert('Search chats clicked')}>
              <span className="sidebar-icon"></span> Search chats
            </div>
            <div className="sidebar-item" onClick={() => user ? alert('Profile clicked') : setIsAuthModalOpen(true)}>
              <span className="sidebar-icon"></span> My profile
            </div>
            <div className="sidebar-item" onClick={() => user ? alert('Documents clicked') : setIsAuthModalOpen(true)}>
              <span className="sidebar-icon"></span> My documents
            </div>
            <div className="sidebar-item" onClick={() => alert('AI-MMI recommendations clicked')}>
              <span className="sidebar-icon"></span> AI-MMI's recommendations
            </div>
            
            <div className="promo-banner">
              <button 
                className="btn btn-custom" 
                onClick={() => setIsHybridPlanModalOpen(true)}
              >
                Subscribe for Hybrid Plan
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Auth Modal */}
      {isAuthModalOpen && (
        <div className="modal-overlay">
          <div className="auth-modal">
            <div className="auth-tabs">
              <div className={`auth-tab ${isLogin ? 'active' : ''}`} onClick={() => setIsLogin(true)}>
                Login
              </div>
              <div className={`auth-tab ${!isLogin ? 'active' : ''}`} onClick={() => setIsLogin(false)}>
                Sign Up
              </div>
            </div>
            
            {isLogin ? (
              <div className="auth-form active">
                <div className="form-group">
                  <label>Email</label>
                  <input 
                    type="email" 
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="Enter your email" 
                  />
                </div>
                <div className="form-group">
                  <label>Password</label>
                  <input 
                    type="password" 
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="Enter your password" 
                  />
                </div>
                <div className="auth-actions">
                  <button className="btn btn-custom-outline" onClick={() => setIsAuthModalOpen(false)}>
                    Cancel
                  </button>
                  <button className="btn btn-custom" onClick={handleLogin}>
                    Login
                  </button>
                </div>
              </div>
            ) : (
              <div className="auth-form">
                <div className="form-group">
                  <label>Full Name</label>
                  <input 
                    type="text" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="Enter your full name" 
                  />
                </div>
                <div className="form-group">
                  <label>Email</label>
                  <input 
                    type="email" 
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="Enter your email" 
                  />
                </div>
                <div className="form-group">
                  <label>Password</label>
                  <input 
                    type="password" 
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="Create a password" 
                  />
                </div>
                <div className="form-group">
                  <label>Confirm Password</label>
                  <input 
                    type="password" 
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    placeholder="Confirm your password" 
                  />
                </div>
                <div className="auth-actions">
                  <button className="btn btn-custom-outline" onClick={() => setIsAuthModalOpen(false)}>
                    Cancel
                  </button>
                  <button className="btn btn-custom" onClick={handleRegister}>
                    Sign Up
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Hybrid Plan Modal */}
      {isHybridPlanModalOpen && (
        <div className="hybrid-plan-modal">
          <div className="hybrid-plan-container">
            <div className="hybrid-plan-header">
              <h2>Choose Your Hybrid Plan</h2>
              <button className="hybrid-plan-close" onClick={() => setIsHybridPlanModalOpen(false)}>
                &times;
              </button>
            </div>
            <div className="hybrid-plan-body">
              <p>Upgrade to a Hybrid Plan to get the best of both worlds - AI assistance combined with expert human support.</p>
              
              <div className="plan-cards">
                <div className="plan-card plan-card-basic">
                  <div className="plan-card-header">
                    <h3>Basic Plan</h3>
                  </div>
                  <div className="plan-card-body">
                    <ul className="plan-features">
                      <li><i className="fas fa-check"></i> Unlimited AI chat</li>
                      <li><i className="fas fa-check"></i> Document analysis (5/month)</li>
                      <li><i className="fas fa-times"></i> No agent access</li>
                    </ul>
                    <div className="plan-price">$9.99/month</div>
                    <button className="plan-select-btn" onClick={() => {
                      if (!user) {
                        setIsHybridPlanModalOpen(false);
                        setIsAuthModalOpen(true);
                      } else {
                        alert('Redirecting to payment for Basic Plan');
                      }
                    }}>
                      Select Basic
                    </button>
                  </div>
                </div>
                
                <div className="plan-card plan-card-premium">
                  <div className="plan-card-header">
                    <h3>Premium Plan</h3>
                  </div>
                  <div className="plan-card-body">
                    <ul className="plan-features">
                      <li><i className="fas fa-check"></i> Everything in Basic</li>
                      <li><i className="fas fa-check"></i> 2 agent consultations/month</li>
                      <li><i className="fas fa-check"></i> Priority support</li>
                    </ul>
                    <div className="plan-price">$29.99/month</div>
                    <button className="plan-select-btn" onClick={() => {
                      if (!user) {
                        setIsHybridPlanModalOpen(false);
                        setIsAuthModalOpen(true);
                      } else {
                        alert('Redirecting to payment for Premium Plan');
                      }
                    }}>
                      Select Premium
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Contact Agent Modal */}
      {isContactAgentModalOpen && (
        <div className="contact-agent-modal">
          <div className="contact-agent-container">
            <div className="contact-agent-header">
              <h2>Contact a Migration Expert</h2>
              <button className="contact-agent-close" onClick={() => setIsContactAgentModalOpen(false)}>
                &times;
              </button>
            </div>
            <div className="contact-agent-body">
              <p>Our network of registered migration agents are ready to assist you.</p>
              <div className="agent-cards">
                <div className="agent-card">
                  <div className="agent-card-header">
                    <h4 className="agent-company">Global Migration Partners</h4>
                  </div>
                  <div className="agent-card-body">
                    <div className="agent-details">
                      <p><i className="fas fa-phone"></i> +1 234 567 890</p>
                      <p><i className="fas fa-envelope"></i> contact@globalmigration.com</p>
                    </div>
                    <button className="agent-contact-btn" onClick={() => {
                      if (!user) {
                        setIsContactAgentModalOpen(false);
                        setIsAuthModalOpen(true);
                      } else {
                        alert('Connecting you with Global Migration Partners');
                      }
                    }}>
                      Contact Agent
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
